// Parse extraction results, prepare for DB upsert + LLM analysis
const result = $input.first().json;
const videos = result.videos || [];

// Create a pipeline run ID
const runId = 'yt-' + Date.now().toString(36);

// Output each video as a separate item for batch processing
const items = videos.map(v => ({
  json: {
    run_id: runId,
    video_id: v.meta.video_id,
    title: v.meta.title,
    channel: v.meta.channel,
    channel_id: v.meta.channel_id,
    published_at: v.meta.published_at,
    duration_seconds: v.meta.duration_seconds,
    view_count: v.meta.view_count,
    description: v.meta.description,
    tags: v.meta.tags || [],
    url: v.meta.url,
    playlist: v.meta.playlist,
    thumbnail: v.meta.thumbnail,
    transcript: v.transcript,
    transcript_language: v.transcript_language,
    has_transcript: !!v.transcript,
    total_videos: result.total_videos,
    with_transcript: result.with_transcript
  }
}));

return items.length > 0 ? items : [{ json: { empty: true, run_id: runId } }];

