INSERT INTO yt_transcripts (video_id, transcript, language)
VALUES (
  '{{ $json.video_id }}',
  {{ $json.transcript ? "'" + $json.transcript.replace(/'/g, "''").substring(0, 100000) + "'" : "NULL" }},
  {{ $json.transcript_language ? "'" + $json.transcript_language + "'" : "NULL" }}
)
ON CONFLICT (video_id) DO UPDATE SET
  transcript = EXCLUDED.transcript,
  language = EXCLUDED.language,
  fetched_at = NOW();

