// Parse LLM analysis response and prepare for DB insert
const item = $input.first().json;
const videoId = $('Has Transcript?').first().json.video_id;

let analysis = {};
try {
  const content = item.choices?.[0]?.message?.content || '{}';
  // Try to extract JSON from the response
  const jsonMatch = content.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    analysis = JSON.parse(jsonMatch[0]);
  }
} catch (e) {
  analysis = {
    technologies: [],
    tools: [],
    frameworks: [],
    relevance_score: 0,
    integration_potential: 'none',
    summary: 'Analysis parse failed: ' + e.message,
    key_takeaways: [],
    platform_relevance: ''
  };
}

return [{
  json: {
    video_id: videoId,
    technologies: analysis.technologies || [],
    tools: analysis.tools || [],
    frameworks: analysis.frameworks || [],
    relevance_score: Math.min(1, Math.max(0, Number(analysis.relevance_score) || 0)),
    integration_potential: ['high', 'medium', 'low', 'none'].includes(analysis.integration_potential) 
      ? analysis.integration_potential : 'none',
    summary: (analysis.summary || '').substring(0, 2000),
    key_takeaways: analysis.key_takeaways || [],
    platform_relevance: (analysis.platform_relevance || '').substring(0, 1000),
    model_used: item.model || 'unknown'
  }
}];
